// // This module compares two 5-bit inputs and outputs signals indicating when x is NOT less than, NOT less than or equal to, NOT greater than, NOT greater than or equal to, NOT equal to, and NOT not equal to y.
module top_module(
    input [4:0] x,
    input [4:0] y,

    output lt,
    output le,
    output gt,
    output ge,
    output eq,
    output ne
);assign lt = x < y;
    assign le = x <= y;
    assign gt = x > y;
    assign ge = x >= y;
    assign eq = x == y;
    assign ne = x != y;
endmodule
